using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design.
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch circle on the xz plane.
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr sketch = sketches->add(rootComp->xZConstructionPlane());
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchLines = sketchCurves->sketchLines();
    if (!sketchLines)
        return false;
    Ptr startPoint = Point3D::create(0, 0, 0);
    Ptr endPoint = Point3D::create(1.0, 0, 0);
    Ptr sketchLine = sketchLines->addByTwoPoints(startPoint, endPoint);

    // Create a open profile.
    Ptr openProfile = rootComp->createOpenProfile(sketchLine);

    // Create an extrusion input.
    Ptr features = rootComp->features();
    if (!features)
        return false;
    Ptr extrudes = features->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extrudeInput =
        extrudes->createInput(openProfile, FeatureOperations::NewBodyFeatureOperation);
    if (!extrudeInput)
        return false;
    extrudeInput->isSolid(false);

    // Define the extent.
    Ptr distance = ValueInput::createByReal(1.0);
    extrudeInput->setDistanceExtent(false, distance);

    // Create the extrusion.
    Ptr extrude = extrudes->add(extrudeInput);
    if (!extrude)
        return false;
    Ptr bodies = extrude->bodies();
    if (!bodies)
        return false;
    Ptr body = bodies->item(0);

    // Get an edge from surface, and add it to object collection.
    Ptr edges = body->edges();
    if (!edges)
        return false;
    Ptr edge = edges->item(0);
    Ptr inputEdges = ObjectCollection::create();
    if (!inputEdges)
        return inputEdges;
    inputEdges->add(edge);

    // Define a distance to extend with 1 cm.
    distance = ValueInput::createByReal(1.0);

    // Create an extend input to be able to define the input needed for an extend.
    Ptr extends = features->extendFeatures();
    if (!extends)
        return false;
    Ptr extendInput =
        extends->createInput(inputEdges, distance, SurfaceExtendTypes::NaturalSurfaceExtendType);
    extendInput->extendAlignment(SurfaceExtendAlignment::FreeEdges);

    // Create an extend feature.
    extends->add(extendInput);


    return true;
}
